// CF16 WF_AUDIENCE_INTELLIGENCE — Sprint S8. Normalize triggers, scope projects.
// Triggers:
//   - Schedule (Sunday 04:00 UTC): scope = all non-paused/archived projects with >=1 published topic
//   - Webhook POST /webhook/audience/intelligence: optional { project_id, force }
// Output: one item per project, pre-loaded with week_of (current Sunday UTC).
// Idempotency check deferred to per-project node (needs to honor force flag per-project).

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || {};
const projectIdFilter = payload.project_id || null;
const force = payload.force === true;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Compute current Sunday UTC as week_of anchor.
// On Sunday, week_of = today. On other days, week_of = most recent Sunday.
const now = new Date();
const dow = now.getUTCDay();
const weekOf = new Date(now);
weekOf.setUTCDate(now.getUTCDate() - dow);
weekOf.setUTCHours(0, 0, 0, 0);
const weekOfDate = weekOf.toISOString().slice(0, 10);

// Scope projects. Tolerate missing status (legacy rows). Include published topic count proxy via fetch.
let projUrl;
if (projectIdFilter) {
  projUrl = `${supabaseUrl}/rest/v1/projects?id=eq.${projectIdFilter}&select=id,name,niche,niche_description,status`;
} else {
  projUrl = `${supabaseUrl}/rest/v1/projects?or=(status.is.null,status.not.in.(paused,archived))&select=id,name,niche,niche_description,status`;
}

const pRes = await fetch(projUrl, { method: 'GET', headers: sbHeaders });
if (!pRes.ok) {
  throw new Error(`Fetch projects failed: HTTP ${pRes.status}: ${(await pRes.text()).slice(0, 300)}`);
}
const projects = await pRes.json();

if (!Array.isArray(projects) || projects.length === 0) {
  return [{
    json: {
      skipped: true,
      reason: projectIdFilter ? `Project ${projectIdFilter} not found` : 'No active projects',
      via_webhook: viaWebhook,
      week_of: weekOfDate,
      http_status: 200
    }
  }];
}

// Filter projects by "has at least one published topic" in one round-trip per project (lightweight count).
const items = [];
for (const p of projects) {
  try {
    const tUrl = `${supabaseUrl}/rest/v1/topics?project_id=eq.${p.id}&status=eq.published&select=id&limit=1`;
    const tRes = await fetch(tUrl, { method: 'GET', headers: sbHeaders });
    if (!tRes.ok) continue;
    const rows = await tRes.json();
    if (!Array.isArray(rows) || rows.length === 0) {
      items.push({
        json: {
          project_id: p.id,
          skipped: true,
          skip_reason: 'no_published_topics_yet',
          week_of: weekOfDate,
          via_webhook: viaWebhook
        }
      });
      continue;
    }
  } catch (_) { continue; }

  items.push({
    json: {
      project_id: p.id,
      name: p.name,
      niche: p.niche,
      niche_description: p.niche_description,
      force,
      via_webhook: viaWebhook,
      week_of: weekOfDate,
      started_at: now.toISOString()
    }
  });
}

if (items.length === 0) {
  return [{
    json: {
      skipped: true,
      reason: 'No projects with published topics',
      via_webhook: viaWebhook,
      week_of: weekOfDate,
      http_status: 200
    }
  }];
}

return items;

// CF16 per-project weekly audience intelligence.
// Stages:
//   1. Idempotency: skip if audience_insights (project_id, week_of) exists and !force.
//   2. Fetch comments for published topics (last 30d) from YouTube Data API v3 — dedup against audience_comments.
//   3. Insert new unclassified audience_comments rows.
//   4. Classify unclassified batch (max 500) via Haiku 4.5 in chunks of 25, PATCH each row.
//   5. Load last 7d of classified non-noise comments; Opus 4.6 synthesizes weekly insights.
//   6. UPSERT audience_insights on (project_id, week_of).
//   7. Log to production_logs.
// Global fetch + $env only. Inline exponential backoff. No WF_RETRY_WRAPPER.

const data = $input.item.json;
if (data.skipped) return $input.item;

const projectId = data.project_id;
const weekOfDate = data.week_of;
const force = data.force === true;
const runStart = Date.now();

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const anthropicKey = $env.ANTHROPIC_API_KEY;
const youtubeApiKey = $env.YOUTUBE_API_KEY || null;

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function sbGet(url, label) {
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) throw new Error(`${label} failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}

async function logProduction(action, status, durationMs, costUsd, retryCount) {
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: null,
        stage: 'audience_intelligence',
        scene_number: null,
        action,
        status,
        duration_ms: durationMs,
        cost_usd: costUsd,
        retry_count: retryCount
      })
    });
  } catch (_) { /* best-effort */ }
}

// Generic Anthropic caller with inline exponential backoff (1s -> 2s -> 4s -> 8s, 30s cap).
// 429 gets a fixed 30s backoff. 4xx (non-429) fails fast.
async function callAnthropic({ model, max_tokens, user_content, maxRetries }) {
  let lastErr = null;
  let retriesTaken = 0;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model,
          max_tokens,
          messages: [{ role: 'user', content: user_content }]
        })
      });
      if (res.ok) {
        const body = await res.json();
        return {
          ok: true,
          text: body.content?.[0]?.text || '',
          input_tokens: body.usage?.input_tokens || 0,
          output_tokens: body.usage?.output_tokens || 0,
          retries: retriesTaken
        };
      }
      const errBody = await res.text();
      lastErr = new Error(`HTTP ${res.status}: ${errBody.slice(0, 300)}`);
      if (res.status === 429) {
        retriesTaken += 1;
        await sleep(30000);
        continue;
      }
      if (res.status >= 400 && res.status < 500) break;
    } catch (e) {
      lastErr = e;
    }
    if (attempt < maxRetries) {
      retriesTaken += 1;
      await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
    }
  }
  return { ok: false, error: lastErr?.message || 'anthropic call failed', retries: retriesTaken };
}

function extractJsonObject(text) {
  if (!text) return null;
  const clean = text.replace(/```json|```/g, '').trim();
  try { return JSON.parse(clean); } catch {}
  const m = clean.match(/\{[\s\S]*\}/);
  if (m) { try { return JSON.parse(m[0]); } catch {} }
  return null;
}

// Inline exponential backoff for YouTube Data API (1s -> 2s -> 4s, max 3).
async function fetchYouTubeComments(videoId) {
  if (!youtubeApiKey) return { ok: false, skipped_no_key: true, items: [] };
  const url = `https://www.googleapis.com/youtube/v3/commentThreads?part=snippet&videoId=${videoId}&maxResults=100&order=relevance&key=${youtubeApiKey}`;
  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const res = await fetch(url, { method: 'GET' });
      if (res.ok) {
        const body = await res.json();
        return { ok: true, items: body.items || [] };
      }
      if (res.status === 403) {
        // Quota or comments disabled — don't retry, surface to caller
        const bodyText = (await res.text()).slice(0, 200);
        return { ok: false, quota_or_disabled: true, status: 403, error: bodyText };
      }
      if (res.status === 404) {
        return { ok: false, not_found: true, status: 404 };
      }
      // 5xx or unexpected — retry
    } catch (_) { /* network blip, retry */ }
    if (attempt < 3) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: 'youtube_fetch_exhausted' };
}

try {
  // ───── 1. Idempotency ─────
  if (!force) {
    const idUrl = `${supabaseUrl}/rest/v1/audience_insights?project_id=eq.${projectId}&week_of=eq.${weekOfDate}&select=id&limit=1`;
    const idRes = await fetch(idUrl, { method: 'GET', headers: sbHeaders });
    if (idRes.ok) {
      const rows = await idRes.json();
      if (Array.isArray(rows) && rows.length > 0) {
        await logProduction('idempotent_skip', 'skipped', Date.now() - runStart, 0, 0);
        return {
          json: {
            project_id: projectId,
            skipped: true,
            skip_reason: `audience_insights already exists for week ${weekOfDate}`,
            week_of: weekOfDate,
            via_webhook: data.via_webhook
          }
        };
      }
    }
  }

  // ───── 2. Load recent published topics (last 30d) ─────
  const thirtyDaysAgo = new Date(Date.now() - 30 * 86400000).toISOString();
  const topicsUrl = `${supabaseUrl}/rest/v1/topics?project_id=eq.${projectId}&status=eq.published&published_at=gte.${encodeURIComponent(thirtyDaysAgo)}&youtube_video_id=not.is.null&select=id,youtube_video_id,seo_title,published_at&order=published_at.desc&limit=20`;
  let recentTopics = [];
  try { recentTopics = await sbGet(topicsUrl, 'fetch recent topics'); } catch (_) { recentTopics = []; }

  let consecutive403s = 0;
  let videosFetched = 0;
  let newCommentsInserted = 0;
  let youtubeAbortedQuota = false;

  // ───── 3. Fetch YouTube comments per video + dedup + insert ─────
  if (recentTopics.length > 0 && youtubeApiKey) {
    for (const topic of recentTopics) {
      const videoId = topic.youtube_video_id;
      if (!videoId) continue;

      if (consecutive403s >= 3) {
        youtubeAbortedQuota = true;
        break;
      }

      const ytRes = await fetchYouTubeComments(videoId);
      videosFetched += 1;

      if (!ytRes.ok) {
        if (ytRes.quota_or_disabled) consecutive403s += 1;
        await sleep(500);
        continue;
      }
      consecutive403s = 0;

      const items = ytRes.items || [];
      if (items.length === 0) { await sleep(500); continue; }

      // Extract top-level comment IDs only
      const incoming = items.map(it => {
        const tlc = it.snippet?.topLevelComment;
        if (!tlc || !tlc.id || !tlc.snippet) return null;
        const s = tlc.snippet;
        return {
          youtube_comment_id: tlc.id,
          author_display_name: (s.authorDisplayName || '').slice(0, 100),
          author_channel_id: (s.authorChannelId?.value || '').slice(0, 50) || null,
          comment_text: s.textOriginal || s.textDisplay || '',
          like_count: Number(s.likeCount) || 0,
          reply_count: Number(it.snippet?.totalReplyCount) || 0,
          published_at: s.publishedAt || null
        };
      }).filter(Boolean).filter(c => c.comment_text && c.comment_text.length > 0);

      if (incoming.length === 0) { await sleep(500); continue; }

      // Dedup against existing audience_comments
      const ids = incoming.map(c => `"${c.youtube_comment_id}"`).join(',');
      const dedupUrl = `${supabaseUrl}/rest/v1/audience_comments?project_id=eq.${projectId}&youtube_comment_id=in.(${ids})&select=youtube_comment_id`;
      let existingIds = new Set();
      try {
        const dRes = await fetch(dedupUrl, { method: 'GET', headers: sbHeaders });
        if (dRes.ok) {
          const rows = await dRes.json();
          existingIds = new Set((rows || []).map(r => r.youtube_comment_id));
        }
      } catch (_) { /* best-effort dedup */ }

      const newRows = incoming
        .filter(c => !existingIds.has(c.youtube_comment_id))
        .map(c => ({
          project_id: projectId,
          topic_id: topic.id,
          youtube_video_id: videoId,
          youtube_comment_id: c.youtube_comment_id,
          author_display_name: c.author_display_name || null,
          author_channel_id: c.author_channel_id,
          comment_text: c.comment_text.slice(0, 4000),
          like_count: c.like_count,
          reply_count: c.reply_count,
          published_at: c.published_at
        }));

      if (newRows.length > 0) {
        try {
          const insRes = await fetch(`${supabaseUrl}/rest/v1/audience_comments`, {
            method: 'POST',
            headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
            body: JSON.stringify(newRows)
          });
          if (insRes.ok) newCommentsInserted += newRows.length;
        } catch (_) { /* continue */ }
      }

      await sleep(500); // Respect YouTube quota cadence
    }
  }

  // ───── 4. Classify unclassified comments via Haiku 4.5 ─────
  const unclsUrl = `${supabaseUrl}/rest/v1/audience_comments?project_id=eq.${projectId}&classification=is.null&order=first_seen_at.asc&limit=500&select=id,comment_text`;
  let unclassified = [];
  try { unclassified = await sbGet(unclsUrl, 'fetch unclassified'); } catch (_) { unclassified = []; }

  const BATCH_SIZE = 25;
  let classifiedCount = 0;
  let haikuCostUsd = 0;
  let haikuRetries = 0;

  for (let i = 0; i < unclassified.length; i += BATCH_SIZE) {
    const batch = unclassified.slice(i, i + BATCH_SIZE);
    const promptText = `Classify each of these YouTube comments into EXACTLY ONE of: question, complaint, praise, suggestion, noise.

Also extract an intent — for questions: the actual question. For complaints: the actual gripe. For suggestions: the actual idea. For praise/noise: empty string.

Also detect language (2-letter ISO code) if not English.

Comments:
${batch.map((c, idx) => `[${idx}] "${(c.comment_text || '').replace(/"/g, '\'').substring(0, 300)}"`).join('\n')}

Return ONLY JSON:
{
  "classifications": [
    {"index": 0, "classification": "<question|complaint|praise|suggestion|noise>", "confidence": <0-1>, "extracted_intent": "<string>", "language_hint": "<iso or null>"}
  ]
}`;

    const callRes = await callAnthropic({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 2000,
      user_content: promptText,
      maxRetries: 4
    });
    haikuRetries += (callRes.retries || 0);

    // Haiku 4.5 pricing: $1/M input, $5/M output
    if (callRes.ok) {
      haikuCostUsd += ((callRes.input_tokens * 1) + (callRes.output_tokens * 5)) / 1_000_000;
    }

    if (!callRes.ok) continue;

    const parsed = extractJsonObject(callRes.text);
    if (!parsed || !Array.isArray(parsed.classifications)) continue;

    const nowIso = new Date().toISOString();
    // Validate + PATCH each
    for (const cls of parsed.classifications) {
      const idx = Number(cls.index);
      if (!Number.isFinite(idx) || idx < 0 || idx >= batch.length) continue;
      const commentRow = batch[idx];
      const label = String(cls.classification || '').toLowerCase().trim();
      if (!['question', 'complaint', 'praise', 'suggestion', 'noise'].includes(label)) continue;
      const conf = Math.max(0, Math.min(1, Number(cls.confidence)));
      const intent = String(cls.extracted_intent || '').slice(0, 500);
      let lang = null;
      if (cls.language_hint && typeof cls.language_hint === 'string') {
        const l = cls.language_hint.trim().toLowerCase().slice(0, 10);
        if (l && l !== 'null' && l !== 'none') lang = l;
      }

      try {
        const pRes = await fetch(`${supabaseUrl}/rest/v1/audience_comments?id=eq.${commentRow.id}`, {
          method: 'PATCH',
          headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
          body: JSON.stringify({
            classification: label,
            classification_confidence: Number.isFinite(conf) ? conf : null,
            extracted_intent: intent || null,
            language_hint: lang,
            classified_at: nowIso,
            classified_by: 'claude-haiku-4-5-20251001'
          })
        });
        if (pRes.ok) classifiedCount += 1;
      } catch (_) { /* continue */ }
    }
  }

  if (unclassified.length > 0) {
    await logProduction('haiku_classify', classifiedCount > 0 ? 'success' : 'partial', Date.now() - runStart, Math.round(haikuCostUsd * 10000) / 10000, haikuRetries);
  }

  // ───── 5. Opus 4.6 weekly synthesis ─────
  const sevenDaysAgo = new Date(Date.now() - 7 * 86400000).toISOString();
  const weeklyUrl = `${supabaseUrl}/rest/v1/audience_comments?project_id=eq.${projectId}&classification=neq.noise&classified_at=gte.${encodeURIComponent(sevenDaysAgo)}&select=youtube_video_id,classification,extracted_intent,like_count,comment_text,author_display_name&limit=800&order=like_count.desc.nullslast`;
  let weekly = [];
  try { weekly = await sbGet(weeklyUrl, 'fetch weekly comments'); } catch (_) { weekly = []; }

  // Full class counts (including noise) for audience_insights storage — separate fetch for totals
  const countsUrl = `${supabaseUrl}/rest/v1/audience_comments?project_id=eq.${projectId}&classification=not.is.null&classified_at=gte.${encodeURIComponent(sevenDaysAgo)}&select=classification&limit=1500`;
  let byClass = { question: 0, complaint: 0, praise: 0, suggestion: 0, noise: 0 };
  let totalAnalyzed = 0;
  try {
    const cArr = await sbGet(countsUrl, 'fetch class counts');
    for (const r of (cArr || [])) {
      const c = r.classification;
      if (c && byClass[c] !== undefined) { byClass[c] += 1; totalAnalyzed += 1; }
    }
  } catch (_) { /* non-fatal */ }

  // Insufficient signal: <10 non-noise classified comments
  const nonNoiseTotal = byClass.question + byClass.complaint + byClass.praise + byClass.suggestion;
  if (nonNoiseTotal < 10) {
    await logProduction('skipped_insufficient_signal', 'skipped', Date.now() - runStart, Math.round(haikuCostUsd * 10000) / 10000, haikuRetries);
    return {
      json: {
        success: false,
        project_id: projectId,
        week_of: weekOfDate,
        skipped: true,
        skip_reason: `insufficient_signal (only ${nonNoiseTotal} non-noise classified comments in last 7 days; need 10+)`,
        new_comments_inserted: newCommentsInserted,
        comments_classified_this_run: classifiedCount,
        videos_fetched: videosFetched,
        youtube_aborted_quota: youtubeAbortedQuota,
        haiku_cost_usd: Math.round(haikuCostUsd * 10000) / 10000,
        via_webhook: data.via_webhook
      }
    };
  }

  // Trim weekly comments for prompt (up to 200 most-liked)
  const weeklyForPrompt = (weekly || []).slice(0, 200);
  const commentsBlock = weeklyForPrompt.map(c => {
    const intent = (c.extracted_intent || c.comment_text || '').slice(0, 200);
    return `[${c.classification}] ${intent} (+${c.like_count || 0})`;
  }).join('\n');

  const synthPrompt = `You are an audience research specialist. Synthesize a week of YouTube comments into actionable audience intelligence for this channel's scriptwriter.

Project: ${data.name || '(unnamed)'} (${data.niche || 'uncategorized niche'})
Comments analyzed: ${totalAnalyzed} (${byClass.question} questions, ${byClass.complaint} complaints, ${byClass.suggestion} suggestions)

Top comments (ordered by like_count, up to 200 included):
${commentsBlock}

TASK — Return JSON only, no markdown:
{
  "recurring_questions": [
    {"question": "<question paraphrased>", "occurrence_count": <int>, "example_comments": ["<quote>"]}
  ],
  "content_complaints": [
    {"complaint": "<issue>", "occurrence_count": <int>, "severity_hint": "<low|medium|high>", "example_comments": ["<quote>"]}
  ],
  "topic_suggestions": [
    {"suggested_title": "<YouTube-style title>", "seed_question": "<which recurring question it answers>", "demand_signal": <0-100>}
  ],
  "audience_persona_summary": "<2-4 sentence paragraph describing WHO they are based on comment evidence>",
  "dominant_persona_traits": {
    "prior_knowledge_hints": ["<concept>"],
    "geographic_hints": ["<region>"],
    "interests": ["<topic>"]
  },
  "vocabulary_level": "<beginner|intermediate|advanced|mixed>",
  "assumed_prior_knowledge": ["<concept>"],
  "frequent_objections": [
    {"objection": "<objection phrasing>", "counter_angle_needed": "<what to address>"}
  ],
  "audience_context_block": "<pre-rendered block for {{audience_context}} injection into script Pass 1, 200-300 words max. Format: 'Our audience ____. They frequently ask ____. They already know ____. Their biggest complaint is ____. Avoid ____.'>"
}

Constraints: up to 5 recurring_questions (most asked), up to 3 content_complaints (most common), 3-5 topic_suggestions, 3-5 assumed_prior_knowledge entries. Use only evidence from the comments above.`;

  const opusStart = Date.now();
  const synthRes = await callAnthropic({
    model: 'claude-opus-4-6',
    max_tokens: 3000,
    user_content: synthPrompt,
    maxRetries: 4
  });
  const opusDuration = Date.now() - opusStart;

  // Opus 4.6 pricing: $15/M input, $75/M output
  let opusCostUsd = 0;
  if (synthRes.ok) {
    opusCostUsd = ((synthRes.input_tokens * 15) + (synthRes.output_tokens * 75)) / 1_000_000;
  }
  opusCostUsd = Math.round(opusCostUsd * 10000) / 10000;

  // Parse + validate with fallback
  let parsed = null;
  if (synthRes.ok) parsed = extractJsonObject(synthRes.text);

  function sanitizeStr(s, maxLen) { return String(s == null ? '' : s).slice(0, maxLen); }
  function sanitizeArrOfStr(arr, maxItems, maxStrLen) {
    if (!Array.isArray(arr)) return [];
    return arr.slice(0, maxItems).map(x => sanitizeStr(x, maxStrLen)).filter(x => x.length > 0);
  }
  function sanitizeArrOfObj(arr, maxItems, mapper) {
    if (!Array.isArray(arr)) return [];
    return arr.slice(0, maxItems).map(mapper).filter(x => x !== null);
  }

  let insightsRow;
  if (parsed) {
    const recurring_questions = sanitizeArrOfObj(parsed.recurring_questions, 5, (q) => {
      const question = sanitizeStr(q?.question, 500);
      if (!question) return null;
      return {
        question,
        occurrence_count: Math.max(1, Math.min(9999, Number(q?.occurrence_count) || 1)),
        example_comments: sanitizeArrOfStr(q?.example_comments, 3, 500)
      };
    });
    const content_complaints = sanitizeArrOfObj(parsed.content_complaints, 3, (c) => {
      const complaint = sanitizeStr(c?.complaint, 500);
      if (!complaint) return null;
      const sev = String(c?.severity_hint || '').toLowerCase().trim();
      return {
        complaint,
        occurrence_count: Math.max(1, Math.min(9999, Number(c?.occurrence_count) || 1)),
        severity_hint: ['low', 'medium', 'high'].includes(sev) ? sev : 'medium',
        example_comments: sanitizeArrOfStr(c?.example_comments, 3, 500)
      };
    });
    const topic_suggestions = sanitizeArrOfObj(parsed.topic_suggestions, 5, (t) => {
      const title = sanitizeStr(t?.suggested_title, 300);
      if (!title) return null;
      return {
        suggested_title: title,
        seed_question: sanitizeStr(t?.seed_question, 500),
        demand_signal: Math.max(0, Math.min(100, Math.round(Number(t?.demand_signal) || 50)))
      };
    });
    const frequent_objections = sanitizeArrOfObj(parsed.frequent_objections, 5, (o) => {
      const obj = sanitizeStr(o?.objection, 500);
      if (!obj) return null;
      return {
        objection: obj,
        counter_angle_needed: sanitizeStr(o?.counter_angle_needed, 500)
      };
    });

    let vocab = String(parsed.vocabulary_level || '').toLowerCase().trim();
    if (!['beginner', 'intermediate', 'advanced', 'mixed'].includes(vocab)) vocab = 'mixed';

    const dominantRaw = parsed.dominant_persona_traits || {};
    const dominant_persona_traits = {
      prior_knowledge_hints: sanitizeArrOfStr(dominantRaw.prior_knowledge_hints, 10, 200),
      geographic_hints: sanitizeArrOfStr(dominantRaw.geographic_hints, 10, 100),
      interests: sanitizeArrOfStr(dominantRaw.interests, 10, 100)
    };

    const assumed_prior_knowledge = sanitizeArrOfStr(parsed.assumed_prior_knowledge, 10, 300);

    insightsRow = {
      project_id: projectId,
      week_of: weekOfDate,
      comments_analyzed: totalAnalyzed,
      questions_count: byClass.question,
      complaints_count: byClass.complaint,
      praise_count: byClass.praise,
      suggestions_count: byClass.suggestion,
      noise_count: byClass.noise,
      recurring_questions,
      content_complaints,
      topic_suggestions,
      audience_persona_summary: sanitizeStr(parsed.audience_persona_summary, 2000) || null,
      dominant_persona_traits,
      vocabulary_level: vocab,
      assumed_prior_knowledge,
      frequent_objections,
      audience_context_block: sanitizeStr(parsed.audience_context_block, 3000) || null,
      generated_by: 'claude-opus-4-6',
      synthesis_cost_usd: opusCostUsd
    };
  } else {
    // Fallback on parse/synthesis failure
    insightsRow = {
      project_id: projectId,
      week_of: weekOfDate,
      comments_analyzed: totalAnalyzed,
      questions_count: byClass.question,
      complaints_count: byClass.complaint,
      praise_count: byClass.praise,
      suggestions_count: byClass.suggestion,
      noise_count: byClass.noise,
      recurring_questions: [],
      content_complaints: [],
      topic_suggestions: [],
      audience_persona_summary: null,
      dominant_persona_traits: { prior_knowledge_hints: [], geographic_hints: [], interests: [] },
      vocabulary_level: 'mixed',
      assumed_prior_knowledge: [],
      frequent_objections: [],
      audience_context_block: 'Audience intelligence synthesis failed this week. Rerun via /webhook/audience/intelligence when ready.',
      generated_by: 'claude-opus-4-6',
      synthesis_cost_usd: opusCostUsd
    };
  }

  // ───── 6. UPSERT audience_insights ─────
  let upsertStatus = 'ok';
  try {
    const upRes = await fetch(`${supabaseUrl}/rest/v1/audience_insights?on_conflict=project_id,week_of`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'resolution=merge-duplicates,return=minimal' },
      body: JSON.stringify(insightsRow)
    });
    if (!upRes.ok) upsertStatus = `insights_upsert HTTP ${upRes.status}: ${(await upRes.text()).slice(0, 200)}`;
  } catch (e) { upsertStatus = `insights_upsert threw: ${e.message}`; }

  // ───── 7. Log opus_synthesis ─────
  const synthesisStatusLog = synthRes.ok && upsertStatus === 'ok' ? 'success' : (upsertStatus === 'ok' ? 'partial' : 'error');
  await logProduction('opus_synthesis', synthesisStatusLog, opusDuration, opusCostUsd, synthRes.retries || 0);

  return {
    json: {
      success: upsertStatus === 'ok' && synthRes.ok,
      project_id: projectId,
      week_of: weekOfDate,
      new_comments_inserted: newCommentsInserted,
      comments_classified_this_run: classifiedCount,
      unclassified_batch_size: unclassified.length,
      videos_fetched: videosFetched,
      youtube_aborted_quota: youtubeAbortedQuota,
      weekly_comments_analyzed: totalAnalyzed,
      by_class: byClass,
      synthesis_ok: synthRes.ok,
      synthesis_error: synthRes.ok ? null : synthRes.error,
      upsert_status: upsertStatus,
      haiku_cost_usd: Math.round(haikuCostUsd * 10000) / 10000,
      opus_cost_usd: opusCostUsd,
      total_cost_usd: Math.round((haikuCostUsd + opusCostUsd) * 10000) / 10000,
      duration_ms: Date.now() - runStart,
      via_webhook: data.via_webhook
    }
  };
} catch (e) {
  await logProduction('project_error', 'error', Date.now() - runStart, 0, 0);
  return {
    json: {
      success: false,
      project_id: projectId,
      week_of: weekOfDate,
      error: e.message,
      via_webhook: data.via_webhook
    }
  };
}

// Aggregate per-project results into a single webhook response.
const items = $input.all().map(i => i.json || {});

// Top-level envelope (nothing to process)
if (items.length === 1 && items[0].skipped && !items[0].project_id) {
  return [{ json: { ...items[0], http_status: 200 } }];
}

const projectsTotal = items.length;
const projectsSucceeded = items.filter(r => r.success === true).length;
const projectsSkipped = items.filter(r => r.skipped === true).length;
const projectsFailed = items.filter(r => r.success === false && !r.skipped).length;

const totalComments = items.reduce((a, r) => a + (Number(r.new_comments_inserted) || 0), 0);
const totalClassified = items.reduce((a, r) => a + (Number(r.comments_classified_this_run) || 0), 0);
const totalHaikuCost = items.reduce((a, r) => a + (Number(r.haiku_cost_usd) || 0), 0);
const totalOpusCost = items.reduce((a, r) => a + (Number(r.opus_cost_usd) || 0), 0);
const totalCost = Math.round((totalHaikuCost + totalOpusCost) * 10000) / 10000;

const viaWebhook = items.some(r => r.via_webhook === true);
const weekOf = items.find(r => r.week_of)?.week_of || null;

return [{
  json: {
    success: projectsSucceeded > 0 || projectsSkipped === projectsTotal,
    week_of: weekOf,
    projects_total: projectsTotal,
    projects_succeeded: projectsSucceeded,
    projects_skipped: projectsSkipped,
    projects_failed: projectsFailed,
    total_new_comments_inserted: totalComments,
    total_comments_classified: totalClassified,
    total_haiku_cost_usd: Math.round(totalHaikuCost * 10000) / 10000,
    total_opus_cost_usd: Math.round(totalOpusCost * 10000) / 10000,
    total_cost_usd: totalCost,
    per_project: items.map(r => ({
      project_id: r.project_id,
      success: r.success === true,
      skipped: r.skipped === true,
      skip_reason: r.skip_reason || null,
      new_comments_inserted: r.new_comments_inserted || 0,
      comments_classified_this_run: r.comments_classified_this_run || 0,
      weekly_comments_analyzed: r.weekly_comments_analyzed || 0,
      synthesis_ok: r.synthesis_ok === true,
      by_class: r.by_class || null,
      total_cost_usd: r.total_cost_usd || 0,
      error: r.error || r.synthesis_error || null,
      upsert_status: r.upsert_status || null
    })),
    via_webhook: viaWebhook,
    finished_at: new Date().toISOString(),
    http_status: 200
  }
}];
